import "..//assets/css/hero.css"; 
import { useState, useEffect } from "react";

const HeroButton = () => {
  const [buttonText, setButtonText] = useState("");
  const [buttonHref, setButtonHref] = useState("#");

  useEffect(() => {
    fetch("../conf/hero/config.json") // Ścieżka do pliku w public
      .then((response) => response.json())
      .then((data) => {
        console.log("Załadowane dane dla hero-button:", data);
        const section = data.find((item) => item["section-id"] === "hero-button");

        if (section) {
          setButtonText(section.text || "Domyślny tekst");
          setButtonHref(section.href || "#");
        }
      })
      .catch((error) => {
        console.error("Błąd ładowania hero-button:", error);
      });
  }, []);

  return (
    <a href={buttonHref} className="hero-button">
      {buttonText}
    </a>
  );
};

export default HeroButton;
